from itertools import combinations

def verify(answer):
    def get_factors(n):
        factors = []
        for i in range(1, int(n**0.5) + 1):
            if n % i == 0:
                factors.append(i)
                if i != n // i:
                    factors.append(n // i)
        return factors

    factors = get_factors(84)
    min_sum = float('inf')
    for r in range(1, len(factors) + 1):
        for combo in combinations(factors, r):
            if math.prod(combo) == 84:
                min_sum = min(min_sum, sum(combo))
    try:
        return int(str(answer).strip()) == min_sum
    except Exception:
        return False

